import{_ as n,o as s,c as a,a as e}from"./app-18841cf9.js";const t={},o=e(`<h1 id="实现网卡切换" tabindex="-1"><a class="header-anchor" href="#实现网卡切换" aria-hidden="true">#</a> 实现网卡切换</h1><blockquote><p>企业开发中经常需要内外网切换，之前使用物理切换器进行网络切换，可行但是占用地方，改用脚本切换实现。</p></blockquote><p>使用步骤：</p><ol><li>增加一个脚本，net-switch.ps1，记得修改两个互相切换的网卡名称。注意：名称为英文，如果默认是中文，则改为英文名称。</li><li>创建一个快捷方式，目标内容为<code>powershell.exe -ExecutionPolicy Bypass -File &quot;C:\\Users\\Administrator\\Documents\\Script\\net-switch.ps1&quot;</code></li><li>将快捷方式放到环境变量获取快捷启动，即可实现快捷切换。</li></ol><p>脚本：switch-net.ps1</p><div class="language-powershell line-numbers-mode" data-ext="powershell"><pre class="language-powershell"><code><span class="token comment"># ================= Config =================</span>
<span class="token variable">$AdapterEth</span>  = <span class="token string">&quot;YIueilEth&quot;</span>
<span class="token variable">$AdapterWifi</span> = <span class="token string">&quot;YIueilWLAN&quot;</span>
<span class="token comment"># ==========================================</span>

<span class="token comment"># Auto elevate to admin if not already</span>
<span class="token keyword">If</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token punctuation">(</span><span class="token namespace">[Security.Principal.WindowsPrincipal]</span><span class="token namespace">[Security.Principal.WindowsIdentity]</span>::GetCurrent<span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span>IsInRole<span class="token punctuation">(</span><span class="token namespace">[Security.Principal.WindowsBuiltInRole]</span> <span class="token string">&quot;Administrator&quot;</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">Start-Process</span> powershell<span class="token punctuation">.</span>exe <span class="token string">&quot;-NoProfile -ExecutionPolicy Bypass -File \`&quot;<span class="token variable">$PSCommandPath</span>\`&quot;&quot;</span> <span class="token operator">-</span>Verb RunAs
    <span class="token keyword">Exit</span>
<span class="token punctuation">}</span>

<span class="token comment"># Get adapter info</span>
<span class="token variable">$ethAdapter</span>  = <span class="token function">Get-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterEth</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
<span class="token variable">$wifiAdapter</span> = <span class="token function">Get-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterWifi</span> <span class="token operator">-</span>ErrorAction SilentlyContinue

<span class="token comment"># Check if adapters exist</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token operator">!</span><span class="token variable">$ethAdapter</span> <span class="token operator">-or</span> <span class="token operator">!</span><span class="token variable">$wifiAdapter</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token function">Write-Host</span> <span class="token string">&quot;ERROR: Adapter not found. Please check names in script.&quot;</span> <span class="token operator">-</span>ForegroundColor Red
    <span class="token function">Write-Host</span> <span class="token string">&quot;Press any key to exit...&quot;</span>
    <span class="token variable">$null</span> = <span class="token variable">$Host</span><span class="token punctuation">.</span>UI<span class="token punctuation">.</span>RawUI<span class="token punctuation">.</span>ReadKey<span class="token punctuation">(</span><span class="token string">&quot;NoEcho,IncludeKeyDown&quot;</span><span class="token punctuation">)</span>
    <span class="token keyword">Exit</span>
<span class="token punctuation">}</span>

<span class="token comment"># Use AdminStatus to check Enabled/Disabled (Up=Enabled, Down=Disabled)</span>
<span class="token variable">$ethEnabled</span>  = <span class="token punctuation">(</span><span class="token variable">$ethAdapter</span><span class="token punctuation">.</span>AdminStatus <span class="token operator">-eq</span> <span class="token string">&quot;Up&quot;</span><span class="token punctuation">)</span>
<span class="token variable">$wifiEnabled</span> = <span class="token punctuation">(</span><span class="token variable">$wifiAdapter</span><span class="token punctuation">.</span>AdminStatus <span class="token operator">-eq</span> <span class="token string">&quot;Up&quot;</span><span class="token punctuation">)</span>

<span class="token comment"># Display current status</span>
<span class="token function">Write-Host</span> <span class="token string">&quot;Current Status:&quot;</span> <span class="token operator">-</span>ForegroundColor Gray
<span class="token function">Write-Host</span> <span class="token string">&quot;  Ethernet : <span class="token function">$<span class="token punctuation">(</span><span class="token variable">$ethAdapter</span><span class="token punctuation">.</span>Status<span class="token punctuation">)</span></span> (Enabled: <span class="token variable">$ethEnabled</span>)&quot;</span> <span class="token operator">-</span>ForegroundColor Gray
<span class="token function">Write-Host</span> <span class="token string">&quot;  WLAN     : <span class="token function">$<span class="token punctuation">(</span><span class="token variable">$wifiAdapter</span><span class="token punctuation">.</span>Status<span class="token punctuation">)</span></span> (Enabled: <span class="token variable">$wifiEnabled</span>)&quot;</span> <span class="token operator">-</span>ForegroundColor Gray
<span class="token function">Write-Host</span> <span class="token string">&quot;&quot;</span>

<span class="token comment"># Toggle Logic</span>
<span class="token keyword">if</span> <span class="token punctuation">(</span><span class="token variable">$ethEnabled</span> <span class="token operator">-and</span> <span class="token operator">!</span><span class="token variable">$wifiEnabled</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment"># Currently Ethernet, switch to WLAN</span>
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Switching to WLAN...&quot;</span> <span class="token operator">-</span>ForegroundColor Cyan
    <span class="token function">Enable-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterWifi</span> <span class="token operator">-</span>Confirm:<span class="token boolean">$false</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
    <span class="token function">Start-Sleep</span> <span class="token operator">-</span>Seconds 1
    <span class="token function">Disable-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterEth</span> <span class="token operator">-</span>Confirm:<span class="token boolean">$false</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Done! Now using WiFi.&quot;</span> <span class="token operator">-</span>ForegroundColor Green
<span class="token punctuation">}</span>
<span class="token keyword">elseif</span> <span class="token punctuation">(</span><span class="token variable">$wifiEnabled</span> <span class="token operator">-and</span> <span class="token operator">!</span><span class="token variable">$ethEnabled</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment"># Currently WLAN, switch to Ethernet</span>
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Switching to Ethernet...&quot;</span> <span class="token operator">-</span>ForegroundColor Yellow
    <span class="token function">Enable-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterEth</span> <span class="token operator">-</span>Confirm:<span class="token boolean">$false</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
    <span class="token function">Start-Sleep</span> <span class="token operator">-</span>Seconds 1
    <span class="token function">Disable-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterWifi</span> <span class="token operator">-</span>Confirm:<span class="token boolean">$false</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Done! Now using Ethernet.&quot;</span> <span class="token operator">-</span>ForegroundColor Green
<span class="token punctuation">}</span>
<span class="token keyword">elseif</span> <span class="token punctuation">(</span><span class="token variable">$ethEnabled</span> <span class="token operator">-and</span> <span class="token variable">$wifiEnabled</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>
    <span class="token comment"># Both enabled, disable WiFi (Priority to Ethernet)</span>
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Both enabled. Disabling WiFi...&quot;</span> <span class="token operator">-</span>ForegroundColor Yellow
    <span class="token function">Disable-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterWifi</span> <span class="token operator">-</span>Confirm:<span class="token boolean">$false</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Done! Now using Ethernet.&quot;</span> <span class="token operator">-</span>ForegroundColor Green
<span class="token punctuation">}</span>
<span class="token keyword">else</span> <span class="token punctuation">{</span>
    <span class="token comment"># Both disabled, enable Ethernet</span>
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Both disabled. Enabling Ethernet...&quot;</span> <span class="token operator">-</span>ForegroundColor Red
    <span class="token function">Enable-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterEth</span> <span class="token operator">-</span>Confirm:<span class="token boolean">$false</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
    <span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Done! Now using Ethernet.&quot;</span> <span class="token operator">-</span>ForegroundColor Green
<span class="token punctuation">}</span>

<span class="token comment"># Wait for changes to apply</span>
<span class="token function">Start-Sleep</span> <span class="token operator">-</span>Seconds 2

<span class="token comment"># Refresh adapter info and display AFTER status</span>
<span class="token variable">$ethAdapter</span>  = <span class="token function">Get-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterEth</span> <span class="token operator">-</span>ErrorAction SilentlyContinue
<span class="token variable">$wifiAdapter</span> = <span class="token function">Get-NetAdapter</span> <span class="token operator">-</span>Name <span class="token variable">$AdapterWifi</span> <span class="token operator">-</span>ErrorAction SilentlyContinue

<span class="token variable">$ethEnabled</span>  = <span class="token punctuation">(</span><span class="token variable">$ethAdapter</span><span class="token punctuation">.</span>AdminStatus <span class="token operator">-eq</span> <span class="token string">&quot;Up&quot;</span><span class="token punctuation">)</span>
<span class="token variable">$wifiEnabled</span> = <span class="token punctuation">(</span><span class="token variable">$wifiAdapter</span><span class="token punctuation">.</span>AdminStatus <span class="token operator">-eq</span> <span class="token string">&quot;Up&quot;</span><span class="token punctuation">)</span>

<span class="token function">Write-Host</span> <span class="token string">&quot;=== AFTER ===&quot;</span> <span class="token operator">-</span>ForegroundColor Green
<span class="token function">Write-Host</span> <span class="token string">&quot;  Ethernet : <span class="token function">$<span class="token punctuation">(</span><span class="token variable">$ethAdapter</span><span class="token punctuation">.</span>Status<span class="token punctuation">)</span></span> (Enabled: <span class="token variable">$ethEnabled</span>)&quot;</span> <span class="token operator">-</span>ForegroundColor Gray
<span class="token function">Write-Host</span> <span class="token string">&quot;  WLAN     : <span class="token function">$<span class="token punctuation">(</span><span class="token variable">$wifiAdapter</span><span class="token punctuation">.</span>Status<span class="token punctuation">)</span></span> (Enabled: <span class="token variable">$wifiEnabled</span>)&quot;</span> <span class="token operator">-</span>ForegroundColor Gray
<span class="token function">Write-Host</span> <span class="token string">&quot;&quot;</span>
<span class="token function">Write-Host</span> <span class="token string">&quot;&gt;&gt;&gt; Switch Complete!&quot;</span> <span class="token operator">-</span>ForegroundColor Green
<span class="token function">Write-Host</span> <span class="token string">&quot;&quot;</span>
<span class="token function">Write-Host</span> <span class="token string">&quot;Press any key to close...&quot;</span> <span class="token operator">-</span>ForegroundColor Gray
<span class="token variable">$null</span> = <span class="token variable">$Host</span><span class="token punctuation">.</span>UI<span class="token punctuation">.</span>RawUI<span class="token punctuation">.</span>ReadKey<span class="token punctuation">(</span><span class="token string">&quot;NoEcho,IncludeKeyDown&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,6),p=[o];function l(i,c){return s(),a("div",null,p)}const u=n(t,[["render",l],["__file","shixianwangkaqiehuan.html.vue"]]);export{u as default};
